import React, { useState, useEffect } from 'react';
import {
  CpuChipIcon,
  ChartBarIcon,
  ArrowTrendingUpIcon,
  MapIcon,
  LightBulbIcon,
  ExclamationTriangleIcon
} from '@heroicons/react/24/outline';

const MLPredictionTab = () => {
  const [activeTab, setActiveTab] = useState('overview');
  const [predictions, setPredictions] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchPredictions();
  }, []);

  const fetchPredictions = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/ml/prediction/overview');
      const data = await response.json();
      setPredictions(data);
    } catch (error) {
      console.error('Error fetching predictions:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Tab Navigation */}
      <div className="border-b border-gray-200">
        <nav className="-mb-px flex space-x-8">
          {[
            { id: 'overview', name: 'Overview', icon: ChartBarIcon },
            { id: 'algorithms', name: 'ML Algorithms', icon: CpuChipIcon },
            { id: 'predictions', name: 'Predictions', icon: ArrowTrendingUpIcon },
            { id: 'hotspots', name: 'Hotspots', icon: MapIcon },
            { id: 'recommendations', name: 'Recommendations', icon: LightBulbIcon }
          ].map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`${activeTab === tab.id
                  ? 'border-blue-500 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                } whitespace-nowrap py-2 px-1 border-b-2 font-medium text-sm flex items-center`}
            >
              <tab.icon className="h-4 w-4 mr-2" />
              {tab.name}
            </button>
          ))}
        </nav>
      </div>

      {/* Tab Content */}
      {activeTab === 'overview' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Current Stats */}
          <div className="bg-white rounded-lg shadow p-6">
            <h3 className="text-lg font-semibold text-gray-900 mb-4">Current Statistics</h3>
            <div className="space-y-3">
              <div className="flex justify-between">
                <span className="text-gray-600">Total Complaints</span>
                <span className="font-semibold">{predictions?.currentStats?.total || 0}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-gray-600">Active</span>
                <span className="font-semibold text-orange-600">{predictions?.currentStats?.active || 0}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-gray-600">Resolved</span>
                <span className="font-semibold text-green-600">{predictions?.currentStats?.resolved || 0}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-gray-600">Resolution Rate</span>
                <span className="font-semibold text-purple-600">{predictions?.currentStats?.resolutionRate || 0}%</span>
              </div>
            </div>
          </div>

          {/* Risk Assessment */}
          <div className="bg-white rounded-lg shadow p-6">
            <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
              <ExclamationTriangleIcon className="h-5 w-5 mr-2 text-red-600" />
              Risk Assessment
            </h3>
            <div className="space-y-3">
              <div>
                <div className="flex justify-between mb-2">
                  <span className="text-gray-600">Overall Risk</span>
                  <span className="font-semibold text-red-600">
                    {predictions?.predictions?.riskAssessment?.overall?.toUpperCase() || 'MEDIUM'}
                  </span>
                </div>
                <div className="w-full bg-gray-200 rounded-full h-2">
                  <div
                    className="bg-red-600 h-2 rounded-full"
                    style={{ width: `${predictions?.predictions?.riskAssessment?.confidence || 75}%` }}
                  ></div>
                </div>
              </div>
              <div className="text-sm text-gray-600">
                Confidence: {predictions?.predictions?.riskAssessment?.confidence || 75}%
              </div>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'algorithms' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {predictions?.algorithms?.map((algo, index) => (
            <div key={index} className="bg-white rounded-lg shadow p-6">
              <div className="flex items-center justify-between mb-4">
                <h3 className="font-semibold text-gray-900">{algo.name}</h3>
                <span className={`px-2 py-1 text-xs rounded-full ${algo.status === 'Active' ? 'bg-green-100 text-green-800' : 'bg-yellow-100 text-yellow-800'
                  }`}>
                  {algo.status}
                </span>
              </div>
              <p className="text-sm text-gray-600 mb-4">{algo.description}</p>
              <div className="space-y-2">
                <div className="flex justify-between">
                  <span className="text-sm text-gray-600">Type:</span>
                  <span className="text-sm font-medium">{algo.type}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-sm text-gray-600">Accuracy:</span>
                  <span className="text-sm font-bold text-green-600">{algo.accuracy}</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {activeTab === 'predictions' && (
        <div className="bg-white rounded-lg shadow p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
            <ArrowTrendingUpIcon className="h-5 w-5 mr-2 text-green-600" />
            7-Day Forecast
          </h3>
          <div className="grid grid-cols-7 gap-4">
            {predictions?.predictions?.weeklyForecast?.map((day, index) => (
              <div key={index} className="text-center">
                <div className="text-sm text-gray-600">
                  {new Date(day.date).toLocaleDateString('en', { weekday: 'short' })}
                </div>
                <div className="mt-2">
                  <div className="text-2xl font-bold text-blue-600">{day.predictedComplaints}</div>
                  <div className="text-xs text-gray-500">predicted</div>
                </div>
                <div className="mt-2">
                  <div className="w-full bg-gray-200 rounded-full h-1">
                    <div
                      className="bg-blue-600 h-1 rounded-full"
                      style={{ width: `${day.confidence}%` }}
                    ></div>
                  </div>
                  <div className="text-xs text-gray-500 mt-1">{day.confidence}%</div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'hotspots' && (
        <div className="bg-white rounded-lg shadow p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
            <MapIcon className="h-5 w-5 mr-2 text-red-600" />
            Predicted Hotspots
          </h3>
          <div className="text-center text-gray-500 py-8">
            <MapIcon className="h-12 w-12 mx-auto text-gray-400 mb-4" />
            <p>Hotspot prediction requires ML service to be running</p>
            <p className="text-sm">Start ML service: cd ml-service && python app.py</p>
          </div>
        </div>
      )}

      {activeTab === 'recommendations' && (
        <div className="bg-white rounded-lg shadow p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center">
            <LightBulbIcon className="h-5 w-5 mr-2 text-yellow-600" />
            Preventive Recommendations
          </h3>
          <div className="space-y-4">
            {predictions?.predictions?.recommendations?.map((rec, index) => (
              <div key={index} className="border-l-4 border-yellow-400 pl-4 py-2">
                <p className="text-gray-700">{rec}</p>
              </div>
            )) || (
                <div className="text-center text-gray-500 py-8">
                  <LightBulbIcon className="h-12 w-12 mx-auto text-gray-400 mb-4" />
                  <p>Recommendations will be available after ML service starts</p>
                </div>
              )}
          </div>
        </div>
      )}
    </div>
  );
};

export default MLPredictionTab;
